# ❌ ANTI-PATTERN: Unbounded Batching (cricket_match processing)
# Waits indefinitely for batch to fill—catastrophic latency
class MatchPredictor:
    def __init__(self, batch_size=32):
        self.batch = []
        self.batch_size = batch_size

    def predict_delivery(self, delivery_data):
        self.batch.append(delivery_data)
        if len(self.batch) == self.batch_size:
            return self._process_batch(self.batch)
        return None  # User blocks forever waiting!

# ✅ BEST PRACTICE: Bounded Batching with Timeout
from queue import Queue
import threading
import time

class OptimizedMatchPredictor:
    def __init__(self, batch_size=32, timeout_ms=50):
        self.batch = []
        self.batch_size = batch_size
        self.timeout_ms = timeout_ms / 1000
        self.last_flush = time.time()
        self.lock = threading.Lock()

    def predict_delivery(self, delivery_data):
        with self.lock:
            self.batch.append(delivery_data)
            time_elapsed = time.time() - self.last_flush

            # Flush if batch full OR timeout exceeded
            if len(self.batch) >= self.batch_size or time_elapsed > self.timeout_ms:
                results = self._process_batch(self.batch)
                self.batch = []
                self.last_flush = time.time()
                return results
        return []  # Return empty while accumulating

    def _process_batch(self, batch):
        # GPU batch inference: 32 deliveries → latency 45ms
        # vs 1 delivery → latency 500ms (50ms overhead per request)
        return [self.model.predict(d) for d in batch]

# ✅ BEST PRACTICE: Load Shedding for SLA Protection
class SLAProtectedPredictor:
    def __init__(self, max_queue=100, priority_threshold=0.8):
        self.queue_size = 0
        self.max_queue = max_queue
        self.priority_threshold = priority_threshold

    def predict_delivery(self, delivery_data, priority=0.5):
        """priority: 1.0 = critical (live match), 0.0 = analysis"""
        if self.queue_size >= self.max_queue:
            # Shed low-priority requests under load
            if priority < self.priority_threshold:
                raise Exception("System overloaded; request rejected")

        self.queue_size += 1
        return self._predict(delivery_data)
